#include <flat_map>
#include <print>
#include <string>
int main() {
    std::flat_map<std::string, int> scores;
    scores["Alice"] = 95;
    scores["Bob"] = 87;
    scores["Carol"] = 92;
    scores["Alice"] = 98;
    for (auto [name, score] : scores)
        std::println("{}: {}", name, score);
    std::println("contains Dave: {}", scores.contains("Dave"));
